export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const survivors = liveCells.filter((cell) => survives(countLiveNeighbors(cell, liveSet)));

  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      if (!liveSet.has(k)) candidates.set(k, [nx, ny]);
    }
  }
  const births: Cell[] = [];
  for (const cell of candidates.values()) {
    if (countLiveNeighbors(cell, liveSet) === 3) births.push(cell);
  }

  return [...survivors, ...births];
}

